interface Payable { public function pay(): float; }

trait Timestamps {
    public ?string $createdAt = null;
    public function touch(): void { $this->createdAt = date('c'); }
}

abstract class Employee implements Payable {
    use Timestamps;
    abstract public function pay(): float;
}

class Contractor extends Employee {
    public function __construct(private float $rate, private int $hours) {}
    public function pay(): float { return $this->rate * $this->hours; }
}
echo (new Contractor(50, 8))->pay(); // 400

