function readLines(string $file): \Generator {
    $fh = fopen($file, 'r');
    try {
        while (($line = fgets($fh)) !== false) {
            yield rtrim($line);
        }
    } finally {
        fclose($fh);
    }
}

foreach (readLines('huge.log') as $line) {
    echo $line, PHP_EOL; // constant memory
}

